To iterate over a `std::map` in C++, you can use a range-based for loop or an iterator-based loop. Here is an example using a range-based for loop:

```c++
#include <iostream>
#include <map>

int main() {
    std::map<std::string, int> myMap = {
        {"apple", 3},
        {"banana", 2},
        {"orange", 1}
    };

    // iterate over map using range-based for loop
    for (const auto& elem : myMap) {
        std::cout << elem.first << " = " << elem.second << std::endl;
    }

    return 0;
}
```

This will output:

```
apple = 3
banana = 2
orange = 1
```

You can also use an iterator-based loop:

```c++
#include <iostream>
#include <map>

int main() {
    std::map<std::string, int> myMap = {
        {"apple", 3},
        {"banana", 2},
        {"orange", 1}
    };

    // iterate over map using iterator-based loop
    for (auto it = myMap.begin(); it != myMap.end(); ++it) {
        std::cout << it->first << " = " << it->second << std::endl;
    }

    return 0;
}
```

This will also output:

```
apple = 3
banana = 2
orange = 1
```

Both approaches achieve the same result, so it's a matter of personal preference which one you choose.

